// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.ArrayList;
import java.util.List;
import java.util.Random;

import org.junit.jupiter.api.Test;

public class LmdbNativeLongArenaTest {

	@Test
	public void appendAndReadBackAcrossBlockBoundaries() {
		LmdbNativeLongArena arena = new LmdbNativeLongArena();
		Random random = new Random(7);
		List<long[]> runs = new ArrayList<>();
		List<Long> offsets = new ArrayList<>();
		// enough varied-size runs to cross several block boundaries, including block-tail waste
		for (int i = 0; i < 5000; i++) {
			long[] run = new long[1 + random.nextInt(97)];
			for (int j = 0; j < run.length; j++) {
				run[j] = random.nextLong();
			}
			long offset = arena.append(run, 0, run.length);
			assertThat(offset).isNotEqualTo(LmdbNativeLongArena.REFUSED);
			runs.add(run);
			offsets.add(offset);
		}
		for (int i = 0; i < runs.size(); i++) {
			long[] expected = runs.get(i);
			long[] actual = new long[expected.length];
			arena.copyTo(offsets.get(i), actual, 0, expected.length);
			assertThat(actual).as("run %d at offset %d", i, offsets.get(i)).isEqualTo(expected);
			assertThat(arena.get(offsets.get(i))).isEqualTo(expected[0]);
		}
	}

	@Test
	public void oversizedRunsGetDedicatedBlocks() {
		LmdbNativeLongArena arena = new LmdbNativeLongArena();
		long smallOffset = arena.append(42L);
		long[] big = new long[LmdbNativeLongArena.BLOCK_LONGS * 2 + 17];
		for (int i = 0; i < big.length; i++) {
			big[i] = i * 31L;
		}
		long bigOffset = arena.append(big, 0, big.length);
		long afterOffset = arena.append(7L);

		assertThat(arena.get(smallOffset)).isEqualTo(42L);
		long[] readBack = new long[big.length];
		arena.copyTo(bigOffset, readBack, 0, big.length);
		assertThat(readBack).isEqualTo(big);
		assertThat(arena.get(afterOffset)).isEqualTo(7L);
	}

	@Test
	public void resetClearsAndStaysConsistent() {
		LmdbNativeLongArena arena = new LmdbNativeLongArena();
		long[] filler = new long[LmdbNativeLongArena.BLOCK_LONGS];
		arena.append(filler, 0, filler.length);
		arena.append(new long[LmdbNativeLongArena.BLOCK_LONGS + 5], 0, LmdbNativeLongArena.BLOCK_LONGS + 5);
		arena.reset();
		assertThat(arena.used()).isZero();

		long first = arena.append(11L);
		assertThat(first).isZero();
		assertThat(arena.get(first)).isEqualTo(11L);

		// an oversized run right after reset must get consistent offsets
		long[] big = new long[LmdbNativeLongArena.BLOCK_LONGS + 3];
		for (int i = 0; i < big.length; i++) {
			big[i] = i + 1000L;
		}
		long bigOffset = arena.append(big, 0, big.length);
		long[] readBack = new long[big.length];
		arena.copyTo(bigOffset, readBack, 0, big.length);
		assertThat(readBack).isEqualTo(big);
		long after = arena.append(13L);
		assertThat(arena.get(after)).isEqualTo(13L);
		assertThat(arena.get(first)).isEqualTo(11L);
	}

	@Test
	public void budgetRefusalLeavesArenaUsable() {
		LmdbNativeLongArena arena = new LmdbNativeLongArena(10);
		long a = arena.append(new long[] { 1, 2, 3 }, 0, 3);
		assertThat(a).isNotEqualTo(LmdbNativeLongArena.REFUSED);
		long refused = arena.append(new long[20], 0, 20);
		assertThat(refused).isEqualTo(LmdbNativeLongArena.REFUSED);
		// refusal must not corrupt state: small appends within budget still work and old data is intact
		long b = arena.append(new long[] { 4, 5 }, 0, 2);
		assertThat(b).isNotEqualTo(LmdbNativeLongArena.REFUSED);
		long[] out = new long[3];
		arena.copyTo(a, out, 0, 3);
		assertThat(out).containsExactly(1, 2, 3);
		arena.copyTo(b, out, 0, 2);
		assertThat(out[0]).isEqualTo(4);
		assertThat(out[1]).isEqualTo(5);
	}
}
